import React, { useState } from 'react'

const Taskcard = ({ task }) => {
    const [subtasks, setSubtasks] = useState([]);

    function addtask() {
        setSubtasks(prev => [...prev, { activity: '', id: Date.now(), completed: false }]);
    }

    function handleSubtaskChange(id, value) {
        setSubtasks(prev =>
            prev.map(sub =>
                sub.id === id ? { ...sub, activity: value } : sub
            )
        );
    }

    function handleBlur(id, value) {
        if (value.trim() === '') {
            setSubtasks(prev => prev.filter(sub => sub.id !== id));
        }
    }

    function toggleCompletion(id) {
        setSubtasks(prev =>
            prev.map(sub =>
                sub.id === id ? { ...sub, completed: !sub.completed } : sub
            )
        );
    }

    function deletetask() {
        // implement if needed
    }

    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>{task.title}</div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button' onClick={addtask}>
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button onClick={deletetask} className='icon-button'>
                                <img className='icon-img' src='./assets/delete.png' alt="Delete" />
                            </button>
                        </div>
                    </div>
                </div>

                <div className='sub-tasks'>
                    {subtasks.map((sub) => (
                        <div className='sub-task-items' key={sub.id}>
                            <input
                                type='checkbox'
                                className='subtask-checkbox'
                                checked={sub.completed}
                                onChange={() => toggleCompletion(sub.id)}
                            />
                            <textarea
                                className={`subtask-input ${sub.completed ? 'completed' : ''}`}
                                value={sub.activity}
                                onChange={(e) => handleSubtaskChange(sub.id, e.target.value)}
                                onBlur={(e) => handleBlur(sub.id, e.target.value)}
                                placeholder='Enter sub task'
                                autoFocus
                                rows={1}
                            />
                        </div>
                    ))}
                </div>
            </div>
            <Stylesheet />
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
        .task-card {
            margin-bottom: 2rem;
            padding: 10px;
            background-color: var(--secondary-color);
            box-sizing: border-box;
            border-radius: 5px;
        }
        .taskcard-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 5px;
            flex-direction: row;
            background-color: var(--secondary-color);
            width: 250px;
            min-height: 50px;
        }
        .task-icons {
            display: flex;
            align-items: center;
        }
        .icon-button {
            background: none;
            border: none;
        }
        .icon-img {
            height: 20px;
            width: 30px;
        }
        .task-title {
            width: 100px;
            word-wrap: break-word;
            overflow-wrap: break-word;
            white-space: normal;
            font-size: 1.8rem;
            font-weight: bold;
        }
        .sub-tasks {
            display: flex;
            justify-content: left;
            align-items: center;
            flex-direction: column;
        }
        .sub-task-items {
            display: flex;
            align-items: flex-start;
            gap: 10px;
            width: 100%;
            margin: 5px 0;
        }
        .subtask-checkbox {
            width: 20px;
            height: 20px;
            accent-color: red;
        }
        .subtask-input {
            resize: none;
            width: 200px;
            font-size: 1rem;
            border: none;
            background-color: var(--secondary-color);
            outline: none;
            font-family: 'Cedarville Cursive', cursive;
            color: var(--text);
            word-wrap: break-word;
